-- Script for DATA_DUMP_RPT_EMPLOY
-- Elimina las propiedades que ya existen para no tener extras sin uso
DELETE [IBC_ISSUER_FILE_TYPE_FIELDS] WHERE ID_ISSUER = 999 AND ID_FILE_TYPE = (SELECT ID_FILE_TYPE FROM TFM_FILE_TYPE WHERE TYPE_NAME = 'DATA_DUMP_RPT_EMPLOY');

SELECT * FROM TFM_FILE_TYPE WHERE TYPE_NAME = 'DATA_DUMP_RPT_EMPLOY' or TYPE_NAME = 'DATA_DUMP_RPT_CLIENT'

-- esta query no retorna DATA_DUMP_RPT_EMPLOY y por eso no genera el archivo
SELECT
    IFT.ID_ISSUER_FILE_TYPE IdIssuerFileType,
    IFT.ID_ISSUER	IdIssuer,
    IFT.ID_FILE_TYPE IdFileType,
    FT.TYPE_NAME,
    IFT.ID_PROCESS IdProcess,
    IFT.FORMAT Format,
    IFT.EXTENSION Extension,
    IFT.ENCODING Encoding,
    IFT.STX_REQUIRED IsStxRequired
FROM TBE_PROCESS P
         INNER JOIN TBE_BATCH_PROCESS BP ON P.ID_PROCESS = BP.ID_PROCESS
         INNER JOIN TFM_FILE_TYPE FT ON FT.ID_PROCESS = BP.ID_PROCESS
         INNER JOIN IBC_ISSUER_FILE_TYPE IFT ON IFT.ID_FILE_TYPE = FT.ID_FILE_TYPE
WHERE P.OPERATION_NAME = 'DataDumpRpt'
  AND IFT.ID_ISSUER = :IdIssuer

-- Datadump Employ fields - Following standard field order from specification

-- ROLLBACK - Elimina todos los registros insertados
 DELETE [IBC_ISSUER_FILE_TYPE_FIELDS] WHERE ID_ISSUER = 999 AND ID_FILE_TYPE = (SELECT ID_FILE_TYPE FROM TFM_FILE_TYPE WHERE TYPE_NAME = 'DATA_DUMP_RPT_EMPLOY');
